/* Generated by Trae Work */
(function () {
  'use strict';

  var cs = getComputedStyle(document.documentElement);
  var colors = {
    bg: cs.getPropertyValue('--bg').trim(),
    bg2: cs.getPropertyValue('--bg2').trim(),
    ink: cs.getPropertyValue('--ink').trim(),
    muted: cs.getPropertyValue('--muted').trim(),
    accent: cs.getPropertyValue('--accent').trim(),
    accent2: cs.getPropertyValue('--accent2').trim(),
    rule: cs.getPropertyValue('--rule').trim()
  };

  var costChart = null;
  var kwhChart = null;

  function makeBaseOption(months) {
    return {
      animation: true,
      animationDuration: 400,
      renderer: 'svg',
      tooltip: {
        appendToBody: true,
        trigger: 'axis',
        backgroundColor: colors.bg2,
        borderColor: colors.rule,
        textStyle: { color: colors.ink }
      },
      grid: {
        left: '10%',
        right: '5%',
        top: '12%',
        bottom: '15%'
      },
      xAxis: {
        type: 'category',
        data: months,
        axisLabel: {
          color: colors.muted,
          rotate: months.length > 8 ? 30 : 0,
          fontSize: 12
        },
        axisLine: { lineStyle: { color: colors.rule } },
        axisTick: { lineStyle: { color: colors.rule } }
      },
      yAxis: {
        type: 'value',
        axisLabel: { color: colors.muted },
        splitLine: { lineStyle: { color: colors.rule, type: 'dashed' } },
        axisLine: { show: false }
      }
    };
  }

  window.__initCharts = function () {
    var data = window.__CHART_DATA || [];
    var months = data.map(function (d) {
      return d.year + '-' + String(d.month).padStart(2, '0');
    });
    var kwhList = data.map(function (d) { return d.kwh; });
    var costList = data.map(function (d) { return d.cost; });

    var baseOption = makeBaseOption(months);

    // 点击柱子跳转到日用电量
    function onChartClick(params) {
      var m = months[params.dataIndex];
      if (m) location.href = 'daily.html?m=' + m;
    }

    // 电费柱状图
    if (!costChart) {
      costChart = echarts.init(document.getElementById('chart-monthly-cost'), null, { renderer: 'svg' });
      costChart.on('click', onChartClick);
      window.addEventListener('resize', function () { costChart.resize(); });
    }
    costChart.setOption(Object.assign({}, baseOption, {
      tooltip: Object.assign({}, baseOption.tooltip, {
        formatter: function (params) {
          return params[0].axisValue + '<br/>' +
            '<span style="color:' + colors.accent2 + '">&#9632;</span> 电费: ' +
            params[0].value.toFixed(2) + ' 元';
        }
      }),
      series: [{
        name: '电费',
        type: 'bar',
        data: costList,
        itemStyle: {
          color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
            { offset: 0, color: colors.accent2 },
            { offset: 1, color: 'rgba(249,115,22,0.3)' }
          ]),
          borderRadius: [4, 4, 0, 0]
        },
        barMaxWidth: 40
      }]
    }), true);

    // 电量折线图
    if (!kwhChart) {
      kwhChart = echarts.init(document.getElementById('chart-monthly-kwh'), null, { renderer: 'svg' });
      kwhChart.on('click', onChartClick);
      window.addEventListener('resize', function () { kwhChart.resize(); });
    }
    kwhChart.setOption(Object.assign({}, baseOption, {
      tooltip: Object.assign({}, baseOption.tooltip, {
        formatter: function (params) {
          return params[0].axisValue + '<br/>' +
            '<span style="color:' + colors.accent + '">&#9679;</span> 电量: ' +
            params[0].value + ' kWh';
        }
      }),
      series: [{
        name: '电量',
        type: 'line',
        data: kwhList,
        smooth: true,
        symbol: 'circle',
        symbolSize: 7,
        lineStyle: { color: colors.accent, width: 2.5 },
        itemStyle: { color: colors.accent },
        areaStyle: {
          color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
            { offset: 0, color: 'rgba(56,189,248,0.35)' },
            { offset: 1, color: 'rgba(56,189,248,0.02)' }
          ])
        }
      }]
    }), true);
  };

  // 首次自动调用
  if (window.__CHART_DATA) {
    window.__initCharts();
  }
})();